// DaemonServiceHandler is an implementation of the bossanova.v1.DaemonService service.
type DaemonServiceHandler interface {
	// Context resolution
	ResolveContext(context.Context, *connect.Request[v1.ResolveContextRequest]) (*connect.Response[v1.ResolveContextResponse], error)
	// Repo management
	ValidateRepoPath(context.Context, *connect.Request[v1.ValidateRepoPathRequest]) (*connect.Response[v1.ValidateRepoPathResponse], error)
	RegisterRepo(context.Context, *connect.Request[v1.RegisterRepoRequest]) (*connect.Response[v1.RegisterRepoResponse], error)
	CloneAndRegisterRepo(context.Context, *connect.Request[v1.CloneAndRegisterRepoRequest]) (*connect.Response[v1.CloneAndRegisterRepoResponse], error)
	ListRepos(context.Context, *connect.Request[v1.ListReposRequest]) (*connect.Response[v1.ListReposResponse], error)
	RemoveRepo(context.Context, *connect.Request[v1.RemoveRepoRequest]) (*connect.Response[v1.RemoveRepoResponse], error)
	UpdateRepo(context.Context, *connect.Request[v1.UpdateRepoRequest]) (*connect.Response[v1.UpdateRepoResponse], error)
	ListRepoPRs(context.Context, *connect.Request[v1.ListRepoPRsRequest]) (*connect.Response[v1.ListRepoPRsResponse], error)
	ListTrackerIssues(context.Context, *connect.Request[v1.ListTrackerIssuesRequest]) (*connect.Response[v1.ListTrackerIssuesResponse], error)
	// Session lifecycle
	CreateSession(context.Context, *connect.Request[v1.CreateSessionRequest], *connect.ServerStream[v1.CreateSessionResponse]) error
	GetSession(context.Context, *connect.Request[v1.GetSessionRequest]) (*connect.Response[v1.GetSessionResponse], error)
	ListSessions(context.Context, *connect.Request[v1.ListSessionsRequest]) (*connect.Response[v1.ListSessionsResponse], error)
	AttachSession(context.Context, *connect.Request[v1.AttachSessionRequest], *connect.ServerStream[v1.AttachSessionResponse]) error
	StopSession(context.Context, *connect.Request[v1.StopSessionRequest]) (*connect.Response[v1.StopSessionResponse], error)
	PauseSession(context.Context, *connect.Request[v1.PauseSessionRequest]) (*connect.Response[v1.PauseSessionResponse], error)
	ResumeSession(context.Context, *connect.Request[v1.ResumeSessionRequest]) (*connect.Response[v1.ResumeSessionResponse], error)
	RetrySession(context.Context, *connect.Request[v1.RetrySessionRequest]) (*connect.Response[v1.RetrySessionResponse], error)
	CloseSession(context.Context, *connect.Request[v1.CloseSessionRequest]) (*connect.Response[v1.CloseSessionResponse], error)
	RemoveSession(context.Context, *connect.Request[v1.RemoveSessionRequest]) (*connect.Response[v1.RemoveSessionResponse], error)
	UpdateSession(context.Context, *connect.Request[v1.UpdateSessionRequest]) (*connect.Response[v1.UpdateSessionResponse], error)
	// Archive / resurrect
	ArchiveSession(context.Context, *connect.Request[v1.ArchiveSessionRequest]) (*connect.Response[v1.ArchiveSessionResponse], error)
	ResurrectSession(context.Context, *connect.Request[v1.ResurrectSessionRequest]) (*connect.Response[v1.ResurrectSessionResponse], error)
	EmptyTrash(context.Context, *connect.Request[v1.EmptyTrashRequest]) (*connect.Response[v1.EmptyTrashResponse], error)
	// Claude chat tracking
	RecordChat(context.Context, *connect.Request[v1.RecordChatRequest]) (*connect.Response[v1.RecordChatResponse], error)
	ListChats(context.Context, *connect.Request[v1.ListChatsRequest]) (*connect.Response[v1.ListChatsResponse], error)
	UpdateChatTitle(context.Context, *connect.Request[v1.UpdateChatTitleRequest]) (*connect.Response[v1.UpdateChatTitleResponse], error)
	DeleteChat(context.Context, *connect.Request[v1.DeleteChatRequest]) (*connect.Response[v1.DeleteChatResponse], error)
	// Chat status (cross-client heartbeat sharing)
	ReportChatStatus(context.Context, *connect.Request[v1.ReportChatStatusRequest]) (*connect.Response[v1.ReportChatStatusResponse], error)
	GetChatStatuses(context.Context, *connect.Request[v1.GetChatStatusesRequest]) (*connect.Response[v1.GetChatStatusesResponse], error)
	GetSessionStatuses(context.Context, *connect.Request[v1.GetSessionStatusesRequest]) (*connect.Response[v1.GetSessionStatusesResponse], error)
	// VCS event delivery (orchestrator → daemon via webhook routing)
	DeliverVCSEvent(context.Context, *connect.Request[v1.DeliverVCSEventRequest]) (*connect.Response[v1.DeliverVCSEventResponse], error)
	// Tmux session management (on-demand)
	EnsureTmuxSession(context.Context, *connect.Request[v1.EnsureTmuxSessionRequest]) (*connect.Response[v1.EnsureTmuxSessionResponse], error)
	// StartAutopilot begins a new autopilot workflow for a plan file.
	StartAutopilot(context.Context, *connect.Request[v1.StartAutopilotRequest]) (*connect.Response[v1.StartAutopilotResponse], error)
	// PauseAutopilot gracefully pauses a running workflow.
	PauseAutopilot(context.Context, *connect.Request[v1.PauseAutopilotRequest]) (*connect.Response[v1.PauseAutopilotResponse], error)
	// ResumeAutopilot resumes a paused workflow.
	ResumeAutopilot(context.Context, *connect.Request[v1.ResumeAutopilotRequest]) (*connect.Response[v1.ResumeAutopilotResponse], error)
	// CancelAutopilot cancels a workflow.
	CancelAutopilot(context.Context, *connect.Request[v1.CancelAutopilotRequest]) (*connect.Response[v1.CancelAutopilotResponse], error)
	// GetAutopilotStatus returns the status of a specific workflow.
	GetAutopilotStatus(context.Context, *connect.Request[v1.GetAutopilotStatusRequest]) (*connect.Response[v1.GetAutopilotStatusResponse], error)
	// ListAutopilotWorkflows lists recent autopilot workflows.
	ListAutopilotWorkflows(context.Context, *connect.Request[v1.ListAutopilotWorkflowsRequest]) (*connect.Response[v1.ListAutopilotWorkflowsResponse], error)
	// StreamAutopilotOutput streams real-time output from a running workflow.
	StreamAutopilotOutput(context.Context, *connect.Request[v1.StreamAutopilotOutputRequest], *connect.ServerStream[v1.StreamAutopilotOutputResponse]) error
}

